const LS='hotel-maintenance-aircon-v6';
let db=JSON.parse(localStorage.getItem(LS)||'null')||INITIAL;
let currentUser=null,currentStoreId=null,currentTab='aircon',editingStoreId=null,editingUserId=null,currentIncidentStatus='progress';
const $=id=>document.getElementById(id);
function save(){localStorage.setItem(LS,JSON.stringify(db));}
function today(){return new Date('2026-06-29T00:00:00');}
function parseDate(s){if(!s)return null; const d=new Date(s+'T00:00:00'); return isNaN(d)?null:d;}
function daysSince(s){let d=parseDate(s); if(!d)return null; return Math.floor((today()-d)/86400000);}
function isValidRoomNumber(v){return /^\d{2,5}[A-Za-z]?$/.test(String(v||'').trim());}
function cleanRooms(){db.stores.forEach(s=>{let seen=new Set();s.rooms=(s.rooms||[]).filter(r=>{let room=String(r.room||'').trim();if(!isValidRoomNumber(room)||seen.has(room))return false;seen.add(room);r.room=room;return true;});});save();}
cleanRooms();
function safeText(v){return String(v??'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));}
function ensureIncidentSamples(){if(Array.isArray(db.incidents)&&db.incidents.length)return;let st=db.stores||[];db.incidents=[
{id:'i1',storeId:st[0]?.id||'h001',room:'201',title:'エアコンから水漏れ',status:'progress',person:'新垣',date:'2026-06-29',memo:'業者手配中'},
{id:'i2',storeId:st[1]?.id||'h002',room:'305',title:'リモコン電池切れ',status:'open',person:'',date:'2026-06-28',memo:'未対応'},
{id:'i3',storeId:st[0]?.id||'h001',room:'402',title:'フィルター清掃完了',status:'done',person:'比嘉',date:'2026-06-20',memo:'対応完了'}
];save();}
ensureIncidentSamples();
function statusFor(s){let days=daysSince(s); if(days===null)return {key:'bad',text:'未洗浄',cls:'bad',days:'-'}; if(days<183)return {key:'ok',text:'半年未満',cls:'ok',days:days+'日'}; if(days<365)return {key:'warn',text:'半年〜1年未満',cls:'warn',days:days+'日'}; return {key:'bad',text:'1年以上',cls:'bad',days:days+'日'};}
function roleName(r){return r==='admin'?'管理者':r==='manager'?'店舗管理者':'スタッフ';}
function storeById(id){return db.stores.find(s=>s.id===id);}
function visibleStores(){return currentUser.role==='admin'?db.stores:db.stores.filter(s=>currentUser.stores.includes(s.id));}
function setTab(tab){currentTab=tab; render();}
function allowedTabs(){let base=[['dashboard','⌂','ダッシュボード'],['incidents','⚒','インシデント'],['aircon','♨','エアコン洗浄']]; if(currentUser.role==='admin')base.push(['stores','▣','店舗管理'],['users','☷','ユーザー管理']); if(currentUser.role==='manager')base.push(['users','☷','ユーザー管理']); return base;}
function login(){let id=$('loginId').value.trim(),pw=$('loginPw').value; let u=db.users.find(x=>x.login===id&&x.password===pw); if(!u){$('loginMsg').textContent='ログインIDまたはパスワードが違います';return} currentUser=u; currentStoreId=visibleStores()[0]?.id||null; $('loginView').classList.add('hidden'); $('appView').classList.remove('hidden'); render();}
function logout(){currentUser=null; localStorage.removeItem('lastUser'); $('appView').classList.add('hidden'); $('loginView').classList.remove('hidden');}
function render(){if(!currentUser)return; let tabs=allowedTabs(); if(!tabs.some(t=>t[0]===currentTab)) currentTab=tabs[0][0]; $('nav').innerHTML=tabs.map(t=>`<button class="${currentTab===t[0]?'active':''}" onclick="setTab('${t[0]}')"><b>${t[1]}</b>${t[2]}</button>`).join(''); $('pageTitle').textContent=tabs.find(t=>t[0]===currentTab)?.[2]||''; let stores=visibleStores(); if(currentTab==='incidents'){if(!currentStoreId||(!stores.some(s=>s.id===currentStoreId)&&currentStoreId!=='all'))currentStoreId='all'; $('storeSelect').innerHTML='<option value="all">全店舗</option>'+stores.map(s=>`<option value="${s.id}">${s.name}</option>`).join(''); $('brand').textContent=currentStoreId==='all'?'全店舗':(storeById(currentStoreId)?.name||'HOTEL').slice(0,5);} else {if(!stores.some(s=>s.id===currentStoreId))currentStoreId=stores[0]?.id||null; $('storeSelect').innerHTML=stores.map(s=>`<option value="${s.id}">${s.name}</option>`).join(''); $('brand').textContent=(storeById(currentStoreId)?.name||'HOTEL').slice(0,5);} $('storeSelect').value=currentStoreId||''; ['dashboard','incidents','aircon','stores','users','reports'].forEach(v=>$(v+'View')?.classList.add('hidden')); $(currentTab+'View')?.classList.remove('hidden'); updateIncidentTabs(); renderRoomsData(); renderActions(); if(currentTab==='aircon')renderAircon(); if(currentTab==='dashboard')renderDashboard(); if(currentTab==='stores')renderStores(); if(currentTab==='users')renderUsers(); if(currentTab==='reports')renderReports(); if(currentTab==='incidents')renderIncidents();}
function renderActions(){$('pageActions').innerHTML='';}
function renderRoomsData(){let s=storeById(currentStoreId); $('roomsData').innerHTML=(s?.rooms||[]).filter(r=>isValidRoomNumber(r.room)).map(r=>`<option value="${r.room}"></option>`).join('');}
function roomFloor(room){let m=String(room||'').match(/^(\d+)/); if(!m)return 'その他'; let n=m[1]; return n.length>=3 ? String(parseInt(n.slice(0,-2),10))+'階' : 'その他';}
function renderAircon(){let s=storeById(currentStoreId); if(!s){$('airconCards').innerHTML='<p>店舗がありません</p>';return} let q=$('airconSearch').value.trim().toLowerCase(); let f=$('airconFilter').value; let rooms=s.rooms.filter(r=>isValidRoomNumber(r.room)).filter(r=>{let st=statusFor(r.latestDate); let text=[r.room,r.latestDate,r.manufacturer,r.worker,r.memo,st.text].join(' ').toLowerCase(); return (!q||text.includes(q))&&(f==='all'||st.key===f);}).sort((a,b)=>String(a.room).localeCompare(String(b.room),'ja',{numeric:true})); let groups={}; rooms.forEach(r=>{let fl=roomFloor(r.room); (groups[fl]||(groups[fl]=[])).push(r);}); let floors=Object.keys(groups).sort((a,b)=>parseInt(a)||999 - (parseInt(b)||999)); $('airconCards').innerHTML=floors.map(fl=>`<section class="floorBlock"><div class="floorTitle">${fl}</div><div class="floorGrid">${groups[fl].map(r=>{let st=statusFor(r.latestDate);return `<div class="airconCard" onclick="openAirconRoom('${r.room.replace(/'/g,"\'")}')"><h3>${r.room}</h3><p>最新：<span class="${st.cls}">${r.latestDate||'未登録'}</span></p><p>状態：<span class="${st.cls}">${st.text}</span></p><p class="small">経過：${st.days}　作業者：${r.worker||'-'}</p><p class="small">メーカー：${r.manufacturer||'-'}</p>${r.memo?`<p class="small">${r.memo}</p>`:''}</div>`}).join('')}</div></section>`).join('')||'<p class="small">表示する部屋がありません。</p>';}
function addAircon(){let s=storeById(currentStoreId); if(!s)return; let room=$('acRoom').value.trim(); if(!room)return alert('部屋番号を入力してください'); let r=s.rooms.find(x=>x.room===room); if(!r){r={room,latestDate:'',manufacturer:'',worker:'',memo:'',history:[]};s.rooms.push(r)} let rec={date:$('acDate').value||new Date().toISOString().slice(0,10),manufacturer:$('acMaker').value.trim(),worker:$('acWorker').value.trim(),memo:$('acMemo').value.trim()}; r.history.push(rec); r.latestDate=rec.date; r.manufacturer=rec.manufacturer; r.worker=rec.worker; r.memo=rec.memo; save(); ['acRoom','acMaker','acDate','acWorker','acMemo'].forEach(id=>$(id).value=''); renderAircon();}
function openAirconRoom(room){let s=storeById(currentStoreId); let r=s.rooms.find(x=>x.room===room); let st=statusFor(r.latestDate); $('airconModalTitle').textContent=`${room}号室 エアコン洗浄`; let hist=[...(r.history||[])].sort((a,b)=>(b.date||'').localeCompare(a.date||'')); $('airconModalBody').innerHTML=`<div class="panel"><p>最新洗浄日：<span class="${st.cls}">${r.latestDate||'未登録'}</span></p><p>状態：<span class="${st.cls}">${st.text}</span></p><p>メーカー：${r.manufacturer||'-'}</p><p>作業者：${r.worker||'-'}</p><p>メモ：${r.memo||'-'}</p></div><h2>洗浄履歴</h2><div class="history">${hist.map((h,i)=>`<div class="historyItem"><b>${h.date||'-'}</b><br>メーカー：${h.manufacturer||'-'}　作業者：${h.worker||'-'}<br>メモ：${h.memo||'-'} <button class="danger" style="float:right" onclick="deleteAirconHistory('${room.replace(/'/g,"\'")}',${i})">削除</button></div>`).join('')||'<p class="small">履歴なし</p>'}</div>`; $('airconModal').classList.add('show');}
function closeAirconModal(){$('airconModal').classList.remove('show');}
function deleteAirconHistory(room,idx){let s=storeById(currentStoreId),r=s.rooms.find(x=>x.room===room); let hist=[...(r.history||[])].sort((a,b)=>(b.date||'').localeCompare(a.date||'')); let target=hist[idx]; r.history=r.history.filter(h=>h!==target); let latest=[...(r.history||[])].sort((a,b)=>(b.date||'').localeCompare(a.date||''))[0]; r.latestDate=latest?.date||''; r.manufacturer=latest?.manufacturer||''; r.worker=latest?.worker||''; r.memo=latest?.memo||''; save(); openAirconRoom(room); renderAircon();}
function renderDashboard(){let s=storeById(currentStoreId)||visibleStores()[0]; if(!s){$('dashboardStats').innerHTML='<p>店舗がありません</p>';return;} let incs=db.incidents.filter(i=>i.storeId===s.id); let open=incs.filter(i=>i.status==='open').length; let progress=incs.filter(i=>i.status==='progress').length; let ok=0,warn=0,bad=0; (s.rooms||[]).filter(r=>isValidRoomNumber(r.room)).forEach(r=>{let k=statusFor(r.latestDate).key; if(k==='ok')ok++; else if(k==='warn')warn++; else bad++;}); $('dashboardStats').innerHTML=`<div class="panel"><h2>店舗情報</h2><p><b>${safeText(s.name)}</b></p><p>住所：${safeText(s.address||'-')}</p><p>電話番号：${s.phone ? `<a href="tel:${String(s.phone).replace(/[^0-9+]/g,'')}" class="phoneLink">${safeText(s.phone)}</a>` : '-'}</p></div><div class="panel"><h2>インシデント</h2><div class="grid"><div class="stat"><span>未対応</span><strong class="bad">${open}</strong></div><div class="stat"><span>対応中</span><strong class="warn">${progress}</strong></div></div></div><div class="panel"><h2>エアコン洗浄</h2><div class="grid"><div class="stat"><span>半年未満</span><strong class="ok">${ok}</strong></div><div class="stat"><span>一年未満</span><strong class="warn">${warn}</strong></div><div class="stat"><span>一年以上・未洗浄</span><strong class="bad">${bad}</strong></div></div></div>`;}
function renderReports(){renderDashboard(); $('reportStats').innerHTML=$('dashboardStats').innerHTML;}
function incidentStatusLabel(v){return v==='progress'?'対応中':v==='done'?'対応完了':'未対応';}
function updateIncidentTabs(){let wrap=$('incidentStatusTabs'); if(!wrap)return; let isIncident=currentTab==='incidents'; wrap.classList.toggle('show',isIncident); if(!isIncident)return; let all=currentStoreId==='all'; if(all&&currentIncidentStatus==='done')currentIncidentStatus='progress'; [...wrap.querySelectorAll('button')].forEach(btn=>{let v=btn.dataset.status; btn.style.display=(all&&v==='done')?'none':''; btn.classList.toggle('active',v===currentIncidentStatus);});}
function setIncidentStatus(v){currentIncidentStatus=v; updateIncidentTabs(); renderIncidents();}
function renderIncidents(){
let all=currentStoreId==='all'; if(all&&currentIncidentStatus==='done')currentIncidentStatus='progress'; updateIncidentTabs();
let allowedIds=visibleStores().map(s=>s.id);
let roomQ=($('incidentRoomSearch')?.value||'').trim().toLowerCase();
let contentQ=($('incidentContentSearch')?.value||'').trim().toLowerCase();
let personQ=($('incidentPersonSearch')?.value||'').trim().toLowerCase();
let from=($('incidentDateFrom')?.value||'');
let to=($('incidentDateTo')?.value||'');
let list=(db.incidents||[]).filter(i=>allowedIds.includes(i.storeId));
if(all)list=list.filter(i=>i.status==='progress'||i.status==='open'); else list=list.filter(i=>i.storeId===currentStoreId);
list=list.filter(i=>i.status===currentIncidentStatus);
if(roomQ)list=list.filter(i=>String(i.room||'').toLowerCase().includes(roomQ));
if(contentQ)list=list.filter(i=>[i.title,i.memo,...((i.progress||[]).map(p=>p.text||''))].join(' ').toLowerCase().includes(contentQ));
if(personQ)list=list.filter(i=>[i.person,...((i.progress||[]).map(p=>p.person||''))].join(' ').toLowerCase().includes(personQ));
if(from)list=list.filter(i=>String(i.date||'')>=from);
if(to)list=list.filter(i=>String(i.date||'')<=to);
list.sort((a,b)=>String(b.date||'').localeCompare(String(a.date||'')));
$('incidentTable').innerHTML='<tr><th>店舗</th><th>部屋</th><th>内容</th><th>状態</th><th>担当</th><th>金額</th><th>発生日</th><th>完了日</th></tr>'+ (list.length?list.map(i=>`<tr class="clickable" onclick="openIncidentModal('${String(i.id).replace(/'/g,"\\'")}')"><td>${safeText(storeById(i.storeId)?.name||'-')}</td><td>${safeText(i.room||'-')}</td><td><b>${safeText(i.title||'-')}</b><br><span class="small">${safeText(i.memo||'')}</span><br><span class="small">履歴 ${((i.progress||[]).length)}件 / 添付 ${((i.media||[]).length)}件</span></td><td>${safeText(incidentStatusLabel(i.status))}</td><td>${safeText(i.person||'-')}</td><td class="money">${formatYen(i.amount)}</td><td>${safeText(i.date||'-')}</td><td>${safeText(i.completeDate||'-')}</td></tr>`).join(''):`<tr><td colspan="8" class="small">表示するインシデントがありません。</td></tr>`);}
function renderStores(){let rows=[...db.stores].sort((a,b)=>String(a.code||'').localeCompare(String(b.code||''),'ja',{numeric:true})).map(s=>`<tr><td>${s.code}</td><td>${s.name}</td><td>${s.rooms.filter(r=>isValidRoomNumber(r.room)).length}室</td><td>${s.address||''}</td><td><button class="iconbtn" onclick="openStoreModal('${s.id}')">編集</button></td></tr>`).join(''); $('storesTable').innerHTML='<tr><th>コード</th><th>ホテル名</th><th>部屋数</th><th>住所</th><th></th></tr>'+rows;}
function openStoreModal(id){editingStoreId=id; let s=storeById(id); $('editStoreName').value=s.name; $('editStoreCode').value=s.code; $('editStoreAddress').value=s.address||''; $('editStorePhone').value=s.phone||''; let validRooms=s.rooms.filter(r=>isValidRoomNumber(r.room)); $('editRoomCount').value=validRooms.length; $('bulkRooms').value=validRooms.map(r=>r.room).join('\n'); buildRoomFields(validRooms.map(r=>r.room)); $('storeModal').classList.add('show');}
function closeStoreModal(){$('storeModal').classList.remove('show');}
function buildRoomFields(vals){$('roomFields').innerHTML=vals.map((v,i)=>`<input class="roomInput" value="${v}" placeholder="部屋${i+1}">`).join(''); checkRooms();}
function checkRooms(){let vals=[...document.querySelectorAll('.roomInput')].map(i=>i.value.trim()); let empty=vals.some(v=>!v), dup=vals.filter((v,i)=>v&&vals.indexOf(v)!==i); $('roomCheck').textContent=empty?'空欄があります':dup.length?'重複：'+[...new Set(dup)].join(', '):''; return !empty&&!dup.length;}
function saveStore(){if(!checkRooms())return alert('部屋番号の空欄または重複を修正してください'); let s=storeById(editingStoreId); s.name=$('editStoreName').value.trim(); s.code=$('editStoreCode').value.trim(); s.address=$('editStoreAddress').value.trim(); s.phone=$('editStorePhone').value.trim(); let old=Object.fromEntries(s.rooms.map(r=>[r.room,r])); s.rooms=[...document.querySelectorAll('.roomInput')].map(i=>i.value.trim()).map(room=>old[room]||{room,latestDate:'',manufacturer:'',worker:'',memo:'',history:[]}); save(); closeStoreModal(); render();}
function renderUsers(){let canAdd=currentUser.role==='admin'||currentUser.role==='manager'; $('userAddBtn').classList.toggle('hidden',!canAdd); let list=db.users.filter(u=>currentUser.role==='admin'||(currentUser.role==='manager'&&u.role==='staff'&&u.stores.some(id=>currentUser.stores.includes(id)))); $('usersTable').innerHTML='<tr><th>名前</th><th>ログインID</th><th>権限</th><th></th></tr>'+list.map(u=>`<tr><td>${u.name}</td><td>${u.login}</td><td>${roleName(u.role)}</td><td><button class="iconbtn" onclick="openUserModal('${u.id}')">編集</button></td></tr>`).join('');}
function openUserModal(id){editingUserId=id||null; let u=id?db.users.find(x=>x.id===id):{login:'',password:'',name:'',role:'staff',stores:[currentStoreId]}; $('uLogin').value=u.login; $('uPassword').value=u.password; $('uName').value=u.name; let roles=currentUser.role==='admin'?[['admin','管理者'],['manager','店舗管理者'],['staff','スタッフ']]:[['staff','スタッフ']]; $('uRole').innerHTML=roles.map(r=>`<option value="${r[0]}">${r[1]}</option>`).join(''); $('uRole').value=u.role==='admin'&&currentUser.role!=='admin'?'staff':u.role; let stores=currentUser.role==='admin'?db.stores:visibleStores(); $('uStores').innerHTML=stores.map(s=>`<label><input type="checkbox" value="${s.id}" ${u.stores.includes(s.id)?'checked':''}> ${s.name}</label>`).join(''); $('userModal').classList.add('show');}
function closeUserModal(){$('userModal').classList.remove('show');}
function saveUser(){let stores=[...$('uStores').querySelectorAll('input:checked')].map(i=>i.value); if(!stores.length)return alert('担当店舗を選択してください'); let role=$('uRole').value; if(currentUser.role==='manager')role='staff'; if(editingUserId){let u=db.users.find(x=>x.id===editingUserId); Object.assign(u,{login:$('uLogin').value.trim(),password:$('uPassword').value,name:$('uName').value.trim(),role,stores})} else {db.users.push({id:'u'+Date.now(),login:$('uLogin').value.trim(),password:$('uPassword').value,name:$('uName').value.trim(),role,stores})} save(); closeUserModal(); renderUsers();}
let editingIncidentId=null;
function formatYen(v){let n=Number(v||0); return n?('¥'+n.toLocaleString()):'-';}
function fileToDataURL(file){return new Promise((resolve,reject)=>{let r=new FileReader(); r.onload=()=>resolve({id:'m'+Date.now()+Math.random().toString(36).slice(2),name:file.name,type:file.type,url:r.result}); r.onerror=reject; r.readAsDataURL(file);});}
async function readMediaFiles(input){let files=[...(input?.files||[])]; let media=[]; for(let f of files)media.push(await fileToDataURL(f)); if(input)input.value=''; return media;}
async function readIncidentProgressMedia(){let media=[]; for(let id of ['ipMediaFiles','ipCameraPhoto','ipCameraVideo'])media.push(...await readMediaFiles($(id))); return media;}
function mediaHTML(m,del){let isVideo=(m.type||'').startsWith('video/'); return `<div class="incidentMediaItem">${isVideo?`<video controls src="${m.url}"></video>`:`<img src="${m.url}" alt="${safeText(m.name||'添付')}">`}<div class="small">${safeText(m.name||'添付')}</div>${del?`<button class="danger" type="button" onclick="${del}">削除</button>`:''}</div>`;}
function renderIncidentMedia(inc){let el=$('incidentMedia'); if(!el)return; el.innerHTML=(inc.media||[]).map((m,idx)=>mediaHTML(m,`deleteIncidentMedia(${idx})`)).join('')||'<p class="small">写真・動画は未登録です。</p>';}
function renderIncidentHistory(inc){
let hist=[...(inc.progress||[])];
$('incidentHistory').innerHTML=hist.length?hist.map((h,idx)=>`<div class="incidentHistoryItem"><div><b>${safeText(h.date||'-')}</b>　${safeText(incidentStatusLabel(h.status||inc.status))}　<span class="money">${formatYen(h.amount)}</span></div><div class="small">記録者：${safeText(h.person||'-')}</div><p>${safeText(h.text||'')}</p><div class="incidentMediaGrid">${(h.media||[]).map(m=>mediaHTML(m,'')).join('')}</div><button class="danger progressDeleteBtn" type="button" data-progress-index="${idx}">削除</button></div>`).join(''):'<p class="small">経過履歴はまだありません。</p>';
}
function normalizeIncident(inc){inc.media=Array.isArray(inc.media)?inc.media:[]; inc.progress=Array.isArray(inc.progress)?inc.progress:[]; inc.amount=inc.amount||''; inc.completeDate=inc.completeDate||''; return inc;}
function currentIncident(){return (db.incidents||[]).find(x=>String(x.id)===String(editingIncidentId));}
function openIncidentModal(id){editingIncidentId=id||null; let allowed=visibleStores(); let inc=id?(db.incidents||[]).find(x=>String(x.id)===String(id)):null; if(!inc){let sid=currentStoreId&&currentStoreId!=='all'?currentStoreId:(allowed[0]?.id||''); inc={storeId:sid,room:'',title:'',status:'open',person:'',date:new Date().toISOString().slice(0,10),memo:'',amount:'',media:[],progress:[]};} normalizeIncident(inc); let isExisting=!!id; $('incidentModalTitle').textContent=isExisting?'インシデント詳細':'インシデント登録'; $('iStore').innerHTML=allowed.map(s=>`<option value="${s.id}">${safeText(s.name)}</option>`).join(''); $('iStore').value=inc.storeId; $('iRoom').value=inc.room||''; $('iTitle').value=inc.title||''; $('iStatus').value=inc.status||'open'; $('iPerson').value=inc.person||''; $('iDate').value=inc.date||new Date().toISOString().slice(0,10); $('iMemo').value=inc.memo||''; ['iStore','iRoom','iTitle','iStatus','iPerson','iDate'].forEach(k=>{$(k).disabled=isExisting;}); $('ipDate').value=new Date().toISOString().slice(0,10); $('ipPerson').value=currentUser?.name||''; $('ipStatus').value=inc.status||'progress'; $('ipAmount').value=''; $('ipText').value=''; toggleProgressAmount(); $('deleteIncidentBtn').classList.toggle('hidden',!id); $('incidentProgressPanel').style.display=id?'block':'none'; renderIncidentMedia(inc); renderIncidentHistory(inc); $('incidentModal').classList.add('show');}
function closeIncidentModal(){$('incidentModal').classList.remove('show');}
async function saveIncident(){let data={storeId:$('iStore').value,room:$('iRoom').value.trim(),title:$('iTitle').value.trim(),status:$('iStatus').value,person:$('iPerson').value.trim(),date:$('iDate').value,memo:$('iMemo').value.trim()}; if(!data.storeId||!data.title)return alert('店舗と件名を入力してください'); if(editingIncidentId){let i=db.incidents.find(x=>String(x.id)===String(editingIncidentId)); if(i){normalizeIncident(i); i.memo=data.memo;}} else {let obj=Object.assign({id:'i'+Date.now(),amount:'',completeDate:'',media:[],progress:[]},data); db.incidents.push(obj); editingIncidentId=obj.id;} save(); openIncidentModal(editingIncidentId); renderIncidents(); renderDashboard();}
function deleteIncident(){if(!editingIncidentId)return; if(!confirm('このインシデントを削除しますか？'))return; db.incidents=db.incidents.filter(x=>String(x.id)!==String(editingIncidentId)); save(); closeIncidentModal(); renderIncidents(); renderDashboard();}
function deleteIncidentMedia(idx){let inc=currentIncident(); if(!inc)return; normalizeIncident(inc); inc.media.splice(idx,1); save(); renderIncidentMedia(inc); renderIncidents();}
async function addIncidentProgress(){let inc=currentIncident(); if(!inc)return alert('先にインシデントを保存してください'); normalizeIncident(inc); let text=$('ipText').value.trim(); let status=$('ipStatus').value; let media=await readIncidentProgressMedia(); let amount=status==='done'?Number($('ipAmount').value||0):0; let entry={id:'p'+Date.now(),date:$('ipDate').value||new Date().toISOString().slice(0,10),person:$('ipPerson').value.trim(),status,text,amount,media}; inc.progress.push(entry); inc.status=entry.status||inc.status; if(entry.status==='done'){inc.completeDate=entry.date; inc.amount=amount;} save(); openIncidentModal(inc.id); renderIncidents(); renderDashboard();}
function toggleProgressAmount(){let el=$('ipAmount'); if(!el)return; let show=$('ipStatus')&&$('ipStatus').value==='done'; el.style.display=show?'':'none'; if(!show)el.value='';}
function recalcIncidentFromProgress(inc){normalizeIncident(inc); let hist=inc.progress; let last=hist[hist.length-1]; if(last){inc.status=last.status||inc.status; let done=[...hist].reverse().find(p=>p.status==='done'); inc.completeDate=done?done.date:''; inc.amount=done?Number(done.amount||0):0;}else{inc.status=inc.status==='done'?'open':inc.status; inc.completeDate=''; inc.amount=0;}}
function deleteIncidentProgress(index){let inc=currentIncident(); if(!inc)return; if(!confirm('この経過履歴を削除しますか？'))return; normalizeIncident(inc); let idx=Number(index); if(Number.isNaN(idx)||idx<0||idx>=inc.progress.length)return; inc.progress.splice(idx,1); recalcIncidentFromProgress(inc); save(); renderIncidentHistory(inc); renderIncidents(); renderDashboard();}
$('loginBtn').onclick=login; $('logoutBtn').onclick=logout; $('storeSelect').onchange=e=>{currentStoreId=e.target.value; render();}; $('addAirconBtn').onclick=addAircon; $('airconSearch').oninput=renderAircon; $('airconFilter').onchange=renderAircon; if($('incidentStatusTabs'))$('incidentStatusTabs').onclick=e=>{let b=e.target.closest('button[data-status]'); if(b)setIncidentStatus(b.dataset.status);}; ['incidentRoomSearch','incidentContentSearch','incidentPersonSearch','incidentDateFrom','incidentDateTo'].forEach(id=>{if($(id))$(id).oninput=renderIncidents;}); $('applyRoomsBtn').onclick=()=>{let pasted=$('bulkRooms').value.split(/\r?\n/).map(s=>s.trim()).filter(Boolean); let n=parseInt($('editRoomCount').value||pasted.length||0); let vals=pasted.slice(0,n); while(vals.length<n)vals.push(''); buildRoomFields(vals);}; $('roomFields').addEventListener('input',checkRooms); $('saveStoreBtn').onclick=saveStore; $('userAddBtn').onclick=()=>openUserModal(); $('saveUserBtn').onclick=saveUser; $('saveIncidentBtn').onclick=saveIncident; $('deleteIncidentBtn').onclick=deleteIncident; if($('ipStatus'))$('ipStatus').onchange=toggleProgressAmount;
if($('incidentHistory'))$('incidentHistory').addEventListener('click',e=>{let b=e.target.closest('.progressDeleteBtn'); if(b)deleteIncidentProgress(b.dataset.progressIndex);});
window.addEventListener('keydown',e=>{if(e.key==='Escape')document.querySelectorAll('.modal.show').forEach(m=>m.classList.remove('show'))});
